# Generates content/unit-NN-cold.json for units 2-10 (Workstream C1).
# Reuses each original unit's vocab + cutscene shell; the crime, dialogue,
# reading and lineup are authored per unit below. Run: python scripts/generate-cold-cases.py
import json, io, os

BASE = os.path.join(os.path.dirname(__file__), "..", "content")

def load(n):
    with io.open(os.path.join(BASE, f"unit-{n:02d}.json"), encoding="utf-8") as f:
        return json.load(f)

# d = dialogue helper
def dlg(npc, avatar, clue, n1, opts1, n2, opts2, end_line, end_msg):
    return {
        "type": "dialogueChoice", "clueReward": clue, "npcName": npc, "npcAvatar": avatar,
        "startNodeId": "start",
        "nodes": [
            {"id": "start", "npcLine": n1, "options": opts1},
            {"id": "info", "npcLine": n2, "options": opts2},
            {"id": "detail", "npcLine": end_line, "isEnd": True, "endMessage": end_msg},
        ],
    }

def opt(text, ok, nxt=None, fb=None):
    o = {"text": text, "isCorrect": ok}
    if ok and nxt: o["nextNodeId"] = nxt
    if not ok and fb: o["feedback"] = fb
    return o

def mc(qid, text, options, ci, es, en):
    return {"id": qid, "text": text, "type": "multiple_choice", "options": options,
            "correctIndex": ci, "explanationEs": es, "explanationEn": en}

def sa(qid, text, answers, es, en):
    return {"id": qid, "text": text, "type": "short_answer", "acceptableAnswers": answers,
            "explanationEs": es, "explanationEn": en}

def sus(sid, name, real, age, desc, seed):
    return {"id": sid, "name": name, "realName": real, "age": age, "description": desc, "imageSeed": seed}

