def build(n, spec):
    orig = load(n)
    cut = next(s for s in orig["stages"] if s["type"] == "cutscene")
    cold_cut = dict(cut)
    cold_cut["videoUrl"] = f"/videos/unit-{n:02d}-cold-intro.mp4"  # text-briefing fallback if absent
    cold_cut["briefingLines"] = spec["briefing"]

    vocab_pairs = [{"spanish": v["spanish"], "english": v["english"]} for v in orig["vocab"][:8]]

    r = spec["reading"]
    reading = {"type": "readingComp", "clueReward": r["clue"], "passage": r["passage"],
               "glossary": r["glossary"], "questions": r["questions"]}

    l = spec["lineup"]
    lineup = {"type": "lineup", "correctSuspectId": l["correct"], "hint": l["hint"], "suspects": l["suspects"]}

    out = {
        "unitNumber": n,
        "country": orig["country"],
        "city": orig.get("city", ""),
        "caseTitle": spec["caseTitle"],
        "caseDescription": spec["caseDescription"],
        "criminalName": spec["criminalName"],
        "bonusClue": spec["bonusClue"],
        "isColdCase": True,
        "vocab": orig["vocab"],
        "stages": [cold_cut, {"type": "vocabMatch", "pairs": vocab_pairs}, spec["dialogue"], reading, lineup],
    }
    path = os.path.join(BASE, f"unit-{n:02d}-cold.json")
    with io.open(path, "w", encoding="utf-8", newline="\n") as f:
        json.dump(out, f, ensure_ascii=False, indent=2)
        f.write("\n")
    print(f"wrote unit-{n:02d}-cold.json ({len(json.dumps(out))} chars)")

for n, spec in COLD.items():
    build(n, spec)
print("done")
